// Pull both ensures-derived sequence equalities into the proof context so
// z3 instantiates the extensional-equality triggers for each run.
assert(post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out));
assert(post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out));

// Both post views equal the same updated sequence, so by transitivity they
